// TestPreClaimIntakeWarnFingerprintEscalatesToOperatorAttention verifies that the
// loop escalates repeated identical pre-claim warn fingerprints across distinct
// bead IDs and emits an operator-attention event that includes the fingerprint.
func TestPreClaimIntakeWarnFingerprintEscalatesToOperatorAttention(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	beadIDs := []string{
		"ddx-intake-warn-1",
		"ddx-intake-warn-2",
		"ddx-intake-warn-3",
		"ddx-intake-warn-4",
		"ddx-intake-warn-5",
		"ddx-intake-warn-6",
	}
	for i, beadID := range beadIDs {
		require.NoError(t, store.Create(&bead.Bead{
			ID:       beadID,
			Title:    "warn intake bead " + beadID,
			Priority: i,
		}))
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				ResultRev: "rev-" + beadID,
			}, nil
		}),
	}

	var eventSink bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		EventSink:                   &eventSink,
		NoReview:                    true,
		PreClaimWarnRepeatThreshold: DefaultPreClaimWarnRepeatThreshold,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeError,
				Reason:  "system_unready",
				Detail:  "readiness check unavailable: shared schema mismatch",
			}, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	// Should process N-1 beads before escalation on the Nth
	assert.Equal(t, DefaultPreClaimWarnRepeatThreshold-1, result.Attempts,
		"must attempt beads up to (but not including) the escalation threshold")
	require.NotNil(t, result.OperatorAttention,
		"must populate OperatorAttention when warn fingerprints escalate")
	assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason)

	// Verify the escalation event in the event sink
	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var escalations []map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		if data["reason"] == "preclaim_warn_repeated" {
			escalations = append(escalations, data)
		}
	}
	require.Len(t, escalations, 1, "exactly one repeated-warn escalation event is expected")
	esc := escalations[0]
	assert.NotEmpty(t, esc["fingerprint"], "escalation payload must include fingerprint")
	assert.Equal(t, float64(DefaultPreClaimWarnRepeatThreshold), esc["count"],
		"count must equal the threshold")
	assert.NotEmpty(t, esc["example_detail"], "escalation payload must include example_detail")
	assert.NotEmpty(t, esc["example_payload"], "escalation payload must include example_payload")
}

